[CmdletBinding(SupportsShouldProcess=$true)]
param([switch]$ClearBrowserMediaCache,[switch]$ResetNetwork,[switch]$RepairWebView2,[switch]$RestartAudioVideoServices,[switch]$Force,[string]$OutputPath="$env:USERPROFILE\Desktop\StreamRepair")
$ErrorActionPreference='Stop';New-Item -ItemType Directory -Path $OutputPath -Force|Out-Null;$Log=Join-Path $OutputPath ("repair-{0:yyyyMMdd-HHmmss}.log"-f(Get-Date));function L($m){"$(Get-Date -Format s) $m"|Tee-Object -FilePath $Log -Append};if(-not($ClearBrowserMediaCache-or$ResetNetwork-or$RepairWebView2-or$RestartAudioVideoServices)){throw'Choose at least one repair action.'}
if($ClearBrowserMediaCache){$p=Get-Process msedge,chrome -ErrorAction SilentlyContinue;if($p-and-not$Force){throw'Close Edge and Chrome or use -Force.'};if($p){$p|Stop-Process -Force};foreach($x in @("$env:LOCALAPPDATA\Microsoft\Edge\User Data\Default\Media Cache","$env:LOCALAPPDATA\Google\Chrome\User Data\Default\Media Cache")){if(Test-Path $x){if($PSCmdlet.ShouldProcess($x,'Clear media cache')){Get-ChildItem $x -Force -ErrorAction SilentlyContinue|Remove-Item -Recurse -Force -ErrorAction SilentlyContinue}}};L'Media cache cleared.'}
if($ResetNetwork-and$PSCmdlet.ShouldProcess('Network stack','Flush DNS and reset Winsock')){Clear-DnsClientCache;netsh winsock reset|Tee-Object -FilePath $Log -Append;L'Network reset completed; reboot may be required.'}
if($RepairWebView2){$setup=Get-ChildItem "$env:ProgramFiles(x86)\Microsoft\EdgeWebView\Application" -Filter setup.exe -Recurse -ErrorAction SilentlyContinue|Select-Object -First 1 -Expand FullName;if(-not$setup){throw'WebView2 setup not found.'};if($PSCmdlet.ShouldProcess('WebView2 Runtime','Repair')){Start-Process $setup '--repair --msedgewebview --system-level' -Wait;L'WebView2 repair completed.'}}
if($RestartAudioVideoServices){foreach($s in'Audiosrv','AudioEndpointBuilder','FrameServer'){if(Get-Service $s -ErrorAction SilentlyContinue){if($PSCmdlet.ShouldProcess($s,'Restart service')){Restart-Service $s -Force -ErrorAction SilentlyContinue;L"Restarted $s"}}}}
L'Repair workflow finished.'